-- SQL Database Setup Script
-- Plataforma de Preparación: Ascenso Docente 2026 - Educación Física
-- Compatible con Supabase (PostgreSQL)

-- 1. CREACIÓN DE TABLAS

-- Tabla: docentes (150 Cuentas de Acceso)
CREATE TABLE IF NOT EXISTS docentes (
    id SERIAL PRIMARY KEY,
    nombre VARCHAR(100) NOT NULL,
    username VARCHAR(100) UNIQUE NOT NULL,
    password VARCHAR(50) NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW()) NOT NULL
);

-- Tabla: simulacros (Los 3 exámenes del MINEDU)
CREATE TABLE IF NOT EXISTS simulacros (
    id SERIAL PRIMARY KEY,
    titulo VARCHAR(150) NOT NULL,
    descripcion TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW()) NOT NULL
);

-- Tabla: preguntas
CREATE TABLE IF NOT EXISTS preguntas (
    id SERIAL PRIMARY KEY,
    simulacro_id INTEGER REFERENCES simulacros(id) ON DELETE CASCADE,
    numero INTEGER NOT NULL,
    enunciado TEXT NOT NULL,
    opcion_a TEXT NOT NULL,
    opcion_b TEXT NOT NULL,
    opcion_c TEXT NOT NULL,
    respuesta_correcta CHAR(1) NOT NULL, -- 'A', 'B', 'C'
    retroalimentacion TEXT NOT NULL,
    puntaje NUMERIC(4, 2) DEFAULT 2.00 NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW()) NOT NULL,
    UNIQUE (simulacro_id, numero)
);

-- Tabla: intentos (Un único intento por examen por docente)
CREATE TABLE IF NOT EXISTS intentos (
    id SERIAL PRIMARY KEY,
    docente_id INTEGER REFERENCES docentes(id) ON DELETE CASCADE,
    simulacro_id INTEGER REFERENCES simulacros(id) ON DELETE CASCADE,
    puntaje_obtenido NUMERIC(5, 2) NOT NULL,
    respuestas_usuario JSONB NOT NULL, -- Respuestas individuales marcadas
    completado_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW()) NOT NULL,
    UNIQUE (docente_id, simulacro_id) -- Garantiza 1 intento único por examen por docente
);

-- Habilitar Row Level Security (RLS) en Supabase (Opcional, para producción)
-- ALTER TABLE docentes ENABLE ROW LEVEL SECURITY;
-- ALTER TABLE simulacros ENABLE ROW LEVEL SECURITY;
-- ALTER TABLE preguntas ENABLE ROW LEVEL SECURITY;
-- ALTER TABLE intentos ENABLE ROW LEVEL SECURITY;


-- 2. INSERCIÓN DE DATOS DE EXÁMENES (SIMULACROS)
ON CONFLICT (id) DO UPDATE SET titulo = EXCLUDED.titulo, descripcion = EXCLUDED.descripcion;



-- SQL Seed File for all 180 questions
-- Plataforma de Preparación: Ascenso Docente 2026 - Educación Física
TRUNCATE TABLE preguntas RESTART IDENTITY CASCADE;






-- 4. INSERCIÓN DE 150 USUARIOS DE PRUEBA
-- Nota: Para poblar las 150 cuentas en Supabase con nombres y credenciales predecibles y listos para usar:
-- Ejecutamos un script anónimo que insertará docentes con formato: docente{N}@edufis2026.pe y contraseña: EF2026_{N} (donde N va de 1 a 150)
-- Esto permite que sean 100% predecibles, consistentes y fáciles de probar.
DO $$
DECLARE
    i INTEGER;
    j INTEGER;
    hash_val BIGINT;
    idx_val INTEGER;
    chars_list TEXT := 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    first_names TEXT[] := ARRAY['Carlos', 'Maria', 'Jose', 'Luis', 'Ana', 'Juan', 'Jorge', 'Rosa', 'Miguel', 'David', 'Pedro', 'Laura', 'Manuel', 'Elena', 'Francisco', 'Carmen', 'Javier', 'Sofia', 'Sandra', 'Roberto'];
    last_names TEXT[] := ARRAY['Mendoza', 'Ramos', 'Garcia', 'Castro', 'Flores', 'Quispe', 'Rojas', 'Sanchez', 'Chavez', 'Diaz', 'Torres', 'Lopez', 'Gonzales', 'Perez', 'Rodriguez', 'Gutierrez', 'Ramirez', 'Cruz', 'Gomez', 'Vasquez'];
    fn TEXT;
    ln1 TEXT;
    ln2 TEXT;
    doc_name TEXT;
    doc_user TEXT;
    doc_pass TEXT;
BEGIN
    FOR i IN 1..150 LOOP
        doc_name := 'Maestro de Educación Física';
        
        -- Formatear username como COD-YYY (ej. COD-001, COD-010, COD-150)
        doc_user := 'COD-' || to_char(i, 'FM000');
        
        -- Generar contraseña determinística (letras y números) idéntica a app.js
        doc_pass := '';
        FOR j IN 0..7 LOOP
            hash_val := (i * 1234567 + j * 9876543) % 1000003;
            idx_val := hash_val % 62;
            doc_pass := doc_pass || substr(chars_list, idx_val + 1, 1);
        END LOOP;
        
        VALUES (doc_name, doc_user, doc_pass)
        ON CONFLICT (username) DO UPDATE
        SET nombre = EXCLUDED.nombre, password = EXCLUDED.password;
    END LOOP;
END $$;